import React, { useState } from 'react';
import '../styles/Employee.css';
import api from '../services/api';
import { useNavigate } from 'react-router-dom';
import AttendanceHistory from './AttendanceHistory';
import Profile from './Profile';

function EmployeeDashboard() {
  const navigate = useNavigate();

  const [activePage, setActivePage] = useState('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const employeeId = localStorage.getItem('employeeId');
  const username = localStorage.getItem('employeename');

  const checkIn = async () => {
    try {
      const response = await api.post(`/attendance/checkin/${employeeId}`);
      const attendanceId = response.data.id;
      localStorage.setItem('attendanceId', attendanceId);
      alert('Checked In Successfully');
    } catch (error) {
      console.log(error);
      alert('Unauthorized');
    }
  };

  const checkOut = async () => {
    const attendanceId = localStorage.getItem('attendanceId');

    try {
      await api.put(`/attendance/checkout/${attendanceId}`);
      alert('Checked Out Successfully');
    } catch (error) {
      console.log(error);
      alert('Unauthorized');
    }
  };

  const logout = () => {
    localStorage.clear();
    navigate('/', { replace: true });
  };

  return (
    <div className="dashboard-container">

      {/* SIDEBAR */}
      <div className={`sidebar ${sidebarOpen ? 'open' : 'collapsed'}`}>

        <div className="sidebar-header">
          {sidebarOpen && <h2>Employee Panel</h2>}

          <button
            className="toggle-btn"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            ☰
          </button>
        </div>

        <ul>
          <li
            className={activePage === 'dashboard' ? 'active' : ''}
            onClick={() => setActivePage('dashboard')}
          >
            🏠 {sidebarOpen && 'Dashboard'}
          </li>

          <li
            className={activePage === 'attendance' ? 'active' : ''}
            onClick={() => setActivePage('attendance')}
          >
            📅 {sidebarOpen && 'Attendance'}
          </li>

          <li
            className={activePage === 'profile' ? 'active' : ''}
            onClick={() => setActivePage('profile')}
          >
            👤 {sidebarOpen && 'Profile'}
          </li>
        </ul>
      </div>

      {/* MAIN CONTENT */}
      <div className={`main-content ${sidebarOpen ? '' : 'full'}`}>

        {/* NAVBAR */}
        <div className="navbar">
         <div className="nav-title">
  <h2>Employee Dashboard</h2>
</div>

          <div className="profile-menu">
            <div className="profile-icon">👤</div>

            <div className="dropdown-menu">
              <p>Welcome, {username}</p>
              <button onClick={logout} className="logout-btn">
                Logout
              </button>
            </div>
          </div>
        </div>

        {/* PAGE CONTENT */}
        {activePage === 'attendance' ? (
          <AttendanceHistory employeeId={employeeId} />
        ) : activePage === 'profile' ? (
          <Profile employeeId={employeeId} />
        ) : (
          <div className="cards-container">
            <div className="card">
              <h3>Check In</h3>
              <button onClick={checkIn}>Check In</button>
            </div>

            <div className="card">
              <h3>Check Out</h3>
              <button onClick={checkOut}>Check Out</button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

export default EmployeeDashboard;