import React, { useState } from 'react';
import '../styles/Dashboard.css';
import { useNavigate } from 'react-router-dom';
import Employee from './Employee';

function AdminDashboard() {
  const navigate = useNavigate();

  const [activePage, setActivePage] = useState('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const username = localStorage.getItem('employeename');

  const logout = () => {
    localStorage.clear();
    navigate('/', { replace: true });
  };

  return (
    <div className="dashboard-container admin-theme">

      {/* SIDEBAR */}
      <div className={`sidebar ${sidebarOpen ? 'open' : 'collapsed'}`}>

        <div className="sidebar-header">
          {sidebarOpen && <h2>Admin Panel</h2>}

          <button
            className="toggle-btn"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            ☰
          </button>
        </div>

        <ul>
          <li
            className={activePage === 'dashboard' ? 'active' : ''}
            onClick={() => setActivePage('dashboard')}
          >
            🏠 {sidebarOpen && 'Dashboard'}
          </li>

          <li
            className={activePage === 'employee' ? 'active' : ''}
            onClick={() => setActivePage('employee')}
          >
            👥 {sidebarOpen && 'Employees'}
          </li>

          <li
            className={activePage === 'attendance' ? 'active' : ''}
            onClick={() => setActivePage('attendance')}
          >
            📅 {sidebarOpen && 'Attendance'}
          </li>

          <li
            className={activePage === 'profile' ? 'active' : ''}
            onClick={() => setActivePage('profile')}
          >
            👤 {sidebarOpen && 'Profile'}
          </li>
        </ul>
      </div>

      {/* MAIN CONTENT */}
      <div className={`main-content ${sidebarOpen ? '' : 'full'}`}>

        {/* NAVBAR */}
        <div className="navbar">
          <div className="nav-title">
            <h2>Admin Dashboard</h2>
          </div>

          <div className="profile-menu">
            <div className="profile-icon">👤</div>

            <div className="dropdown-menu">
              <p>Welcome, {username}</p>
              <button onClick={logout} className="logout-btn">
                Logout
              </button>
            </div>
          </div>
        </div>

        {/* PAGE CONTENT */}
        {activePage === 'dashboard' && (
          <div className="cards-container">
            <div className="card">
              <h3>Total Employees</h3>
              <button>View</button>
            </div>

            <div className="card">
              <h3>Today Present</h3>
              <button>View</button>
            </div>

            <div className="card">
              <h3>Checked In</h3>
              <button>View</button>
            </div>

            <div className="card">
              <h3>Checked Out</h3>
              <button>View</button>
            </div>
          </div>
        )}

       {activePage === 'employee' && (
  <Employee/>
)}

        {activePage === 'attendance' && (
          <div className="cards-container">
            <div className="card">
              <h3>Attendance Reports</h3>
              <button>View</button>
            </div>
          </div>
        )}

        {activePage === 'profile' && (
          <div className="cards-container">
            <div className="card">
              <h3>Admin Profile</h3>
              <button>Open</button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

export default AdminDashboard;