import React, { useEffect, useState } from 'react';
import api from '../services/api';
import '../styles/Profile.css';

function Profile({ employeeId }) {

  const [user, setUser] = useState({});

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await api.get(`/users/profile/${employeeId}`);
      setUser(response.data);
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div className="profile-container">

      <div className="profile-card">
        <h2 className="profile-title">Employee Profile</h2>

        <div className="profile-grid">

          <div className="profile-field">
            <label>Employee ID</label>
            <div className="profile-box">{user.id}</div>
          </div>

          <div className="profile-field">
            <label>First Name</label>
            <div className="profile-box">{user.firstname}</div>
          </div>

          <div className="profile-field">
            <label>Middle Name</label>
            <div className="profile-box">{user.middlename}</div>
          </div>

          <div className="profile-field">
            <label>Last Name</label>
            <div className="profile-box">{user.lastname}</div>
          </div>

          <div className="profile-field">
            <label>Email</label>
            <div className="profile-box">{user.email}</div>
          </div>

          <div className="profile-field">
            <label>Mobile</label>
            <div className="profile-box">{user.mobileNo}</div>
          </div>

          <div className="profile-field">
            <label>Date Of Birth</label>
            <div className="profile-box">
              {user.dob ? new Date(user.dob).toLocaleDateString() : '-'}
            </div>
          </div>

          <div className="profile-field">
            <label>Age</label>
            <div className="profile-box">{user.age}</div>
          </div>

          <div className="profile-field full-width">
            <label>Address</label>
            <div className="profile-box">{user.address}</div>
          </div>

        </div>
      </div>

    </div>
  );
}

export default Profile;