import React, { useEffect, useState } from 'react';
import api from '../services/api';
import '../styles/Employee.css';

function Employee() {

  const [employees, setEmployees] = useState([]);

  const [form, setForm] = useState({
    id: null,
    username: '',
    password: '',
    role: 2,
    firstname: '',
    middlename: '',
    lastname: '',
    email: '',
    address: '',
    dob: '',
    mobileNo: '',
    age: ''
  });

  const [isEdit, setIsEdit] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [viewEmp, setViewEmp] = useState(null);

  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [page, setPage] = useState(0);
  const [size] = useState(5);
  const [totalPages, setTotalPages] = useState(0);

  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setDebouncedSearch(search), 500);
    return () => clearTimeout(t);
  }, [search]);

  useEffect(() => {
    fetchEmployees();
  }, [page, debouncedSearch]);

  const fetchEmployees = async () => {
    try {
      setLoading(true);
      const res = await api.get(
        `/users/all?page=${page}&size=${size}&search=${debouncedSearch}`
      );
      setEmployees(res.data.content);
      setTotalPages(res.data.totalPages);
    } finally {
      setLoading(false);
    }
  };

  const saveEmployee = async () => {
    try {
      setLoading(true);
      await api.post('/users/save', form);
      fetchEmployees();
      clearForm();
    } finally {
      setLoading(false);
    }
  };

const editEmployee = (emp) => {
  setForm({
    ...emp,
    dob: emp.dob ? emp.dob.split("T")[0] : ""
  });

  setIsEdit(true);
  setShowForm(true);
};
  const deleteEmployee = async (id) => {
    try {
      setLoading(true);
      await api.post('/users/delete', { id });
      fetchEmployees();
    } finally {
      setLoading(false);
    }
  };

  const clearForm = () => {
    setForm({
      id: null,
      username: '',
      password: '',
      role: 2,
      firstname: '',
      middlename: '',
      lastname: '',
      email: '',
      address: '',
      dob: '',
      mobileNo: '',
      age: ''
    });
    setIsEdit(false);
    setShowForm(false);
  };

  return (
    <div className="employees-container">

      {/* TOP BAR */}
      <div className="top-bar">
        <input
          placeholder="Search employee..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setPage(0);
          }}
        />

        <button onClick={() => setShowForm(true)}>+ Add Employee</button>
      </div>

      {/* LOADER */}
      {loading && <div className="loader-container"><div className="loader"></div></div>}

      {/* TABLE */}
      {!showForm && (
        <>
          <table className="employee-table">
            <thead>
              <tr>
                <th>Username</th>
                <th>Name</th>
                <th>Role</th>
                <th>Email</th>
                <th>Mobile</th>
                <th>Actions</th>
              </tr>
            </thead>

            <tbody>
              {employees.map((emp) => (
                <tr key={emp.id}>
                  <td>{emp.username}</td>
                  <td>{emp.firstname} {emp.lastname}</td>
                  <td>{emp.role === "1" ? "Admin" : "Employee"}</td>
                  <td>{emp.email}</td>
                  <td>{emp.mobileNo}</td>
                  <td>
                    <button onClick={() => editEmployee(emp)}>Edit</button>
                    <button onClick={() => setViewEmp(emp)}>View</button>
                    <button onClick={() => deleteEmployee(emp.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* PAGINATION */}
          <div className="pagination">
            <button disabled={page === 0} onClick={() => setPage(page - 1)}>Prev</button>
            <span>{page + 1} / {totalPages}</span>
            <button disabled={page + 1 === totalPages} onClick={() => setPage(page + 1)}>Next</button>
          </div>
        </>
      )}

      {/* ADD / EDIT MODAL */}
      {showForm && (
        <div className="modal-overlay">
          <div className="modal">

            <h3>{isEdit ? "Edit Employee" : "Add Employee"}</h3>

            <div className="form-grid">

              {[
                "username",
                "password",
                "firstname",
                "middlename",
                "lastname",
                "email",
                "address",
                "mobileNo",
                "age"
              ].map((key) => (
                <div className="floating" key={key}>
                  <input
                    value={form[key]}
                    onChange={(e) =>
                      setForm({ ...form, [key]: e.target.value })
                    }
                    placeholder=" "
                  />
                  <label>{key}</label>
                </div>
              ))}

              {/* ROLE */}
              <div className="floating">
                <select
                  value={form.role}
                  onChange={(e) =>
                    setForm({ ...form, role: Number(e.target.value) })
                  }
                  disabled={isEdit}
                >
                  <option value={2}>Employee</option>
                  <option value={1}>Admin</option>
                </select>
                <label>Role</label>
              </div>

              {/* DOB */}
              <div className="floating">
                <input
                  type="date"
                  value={form.dob}
                  onChange={(e) =>
                    setForm({ ...form, dob: e.target.value })
                  }
                />
                <label>Date of Birth</label>
              </div>

            </div>

            <div className="modal-actions">
              <button onClick={saveEmployee}>
                {isEdit ? "Update" : "Add"}
              </button>
              <button onClick={clearForm}>Cancel</button>
            </div>

          </div>
        </div>
      )}

      {/* VIEW MODAL */}
      {viewEmp && (
        <div className="modal-overlay">
          <div className="modal">

            <h3>Employee Details</h3>

            <div className="form-grid">

              <div className="floating">
                <input value={viewEmp.username} disabled />
                <label>Username</label>
              </div>

              <div className="floating">
                <input value={viewEmp.firstname} disabled />
                <label>First Name</label>
              </div>

              <div className="floating">
                <input value={viewEmp.lastname} disabled />
                <label>Last Name</label>
              </div>

              <div className="floating">
                <input value={viewEmp.role === "1" ? "Admin" : "Employee"} disabled />
                <label>Role</label>
              </div>

              <div className="floating">
                <input value={viewEmp.email} disabled />
                <label>Email</label>
              </div>

              <div className="floating">
                <input value={viewEmp.mobileNo} disabled />
                <label>Mobile</label>
              </div>

              <div className="floating">
                <input value={viewEmp.address} disabled />
                <label>Address</label>
              </div>

              <div className="floating">
                <input value={formatDate(viewEmp.dob)} disabled />
                <label>DOB</label>
              </div>

              <div className="floating">
                <input value={viewEmp.age} disabled />
                <label>Age</label>
              </div>

            </div>

            <div className="modal-actions">
              <button onClick={() => setViewEmp(null)}>Close</button>
            </div>

          </div>
        </div>
      )}

    </div>
  );
}

const formatDate = (dateStr) => {
  try {
    return dateStr ? new Date(dateStr).toISOString().split("T")[0] : "";
  } catch {
    return "";
  }
};
export default Employee;